2697 template <typename Opnd_t> struct Signum_match {
2698   Opnd_t Val;
2699   Signum_match(const Opnd_t &V) : Val(V) {}
2700 
2701   template <typename OpTy> bool match(OpTy *V) {
2702     unsigned TypeSize = V->getType()->getScalarSizeInBits();
2703     if (TypeSize == 0)
2704       return false;
2705 
2706     unsigned ShiftWidth = TypeSize - 1;
2707     Value *OpL = nullptr, *OpR = nullptr;
2708 
2709     // This is the representation of signum we match:
2710     //
2711     //  signum(x) == (x >> 63) | (-x >>u 63)
2712     //
2713     // An i1 value is its own signum, so it's correct to match
2714     //
2715     //  signum(x) == (x >> 0)  | (-x >>u 0)
2716     //
2717     // for i1 values.
2718 
2719     auto LHS = m_AShr(m_Value(OpL), m_SpecificInt(ShiftWidth));
2720     auto RHS = m_LShr(m_Neg(m_Value(OpR)), m_SpecificInt(ShiftWidth));
2721     auto Signum = m_Or(LHS, RHS);
2722 
2723     return Signum.match(V) && OpL == OpR && Val.match(OpL);
2724   }
2725 };
2726 
2727 /// Matches a signum pattern.
2728 ///
2729 /// signum(x) =
2730 ///      x >  0  ->  1
2731 ///      x == 0  ->  0
2732 ///      x <  0  -> -1
2733 template <typename Val_t> inline Signum_match<Val_t> m_Signum(const Val_t &V) {
2734   return Signum_match<Val_t>(V);
2735 }
2736 
2737 template <int Ind, typename Opnd_t> struct ExtractValue_match {
2738   Opnd_t Val;
2739   ExtractValue_match(const Opnd_t &V) : Val(V) {}
2740 
2741   template <typename OpTy> bool match(OpTy *V) {
2742     if (auto *I = dyn_cast<ExtractValueInst>(V)) {
2743       // If Ind is -1, don't inspect indices
2744       if (Ind != -1 &&
2745           !(I->getNumIndices() == 1 && I->getIndices()[0] == (unsigned)Ind))
2746         return false;
2747       return Val.match(I->getAggregateOperand());
2748     }
2749     return false;
2750   }
2751 };
2752 
2753 /// Match a single index ExtractValue instruction.
2754 /// For example m_ExtractValue<1>(...)
2755 template <int Ind, typename Val_t>
2756 inline ExtractValue_match<Ind, Val_t> m_ExtractValue(const Val_t &V) {
2757   return ExtractValue_match<Ind, Val_t>(V);
2758 }
2759 
2760 /// Match an ExtractValue instruction with any index.
2761 /// For example m_ExtractValue(...)
2762 template <typename Val_t>
2763 inline ExtractValue_match<-1, Val_t> m_ExtractValue(const Val_t &V) {
2764   return ExtractValue_match<-1, Val_t>(V);
2765 }
