2767 /// Matcher for a single index InsertValue instruction.
2768 template <int Ind, typename T0, typename T1> struct InsertValue_match {
2769   T0 Op0;
2770   T1 Op1;
2771 
2772   InsertValue_match(const T0 &Op0, const T1 &Op1) : Op0(Op0), Op1(Op1) {}
2773 
2774   template <typename OpTy> bool match(OpTy *V) {
2775     if (auto *I = dyn_cast<InsertValueInst>(V)) {
2776       return Op0.match(I->getOperand(0)) && Op1.match(I->getOperand(1)) &&
2777              I->getNumIndices() == 1 && Ind == I->getIndices()[0];
2778     }
2779     return false;
2780   }
2781 };
2782 
2783 /// Matches a single index InsertValue instruction.
2784 template <int Ind, typename Val_t, typename Elt_t>
2785 inline InsertValue_match<Ind, Val_t, Elt_t> m_InsertValue(const Val_t &Val,
2786                                                           const Elt_t &Elt) {
2787   return InsertValue_match<Ind, Val_t, Elt_t>(Val, Elt);
2788 }
